// Script Continued Below
var TaskerWidgetIconsAndMessages = Class.create();
TaskerWidgetIconsAndMessages.prototype = {
    initialize: function(widgetId) {
		this.widgetId = widgetId;
    },

	PREFERENCE_FAVORITE: 'DTechApps.Tasker.FavoriteOU',
	PREFERENCE_PERCENT: 'DTechApps.Tasker.selectPercent',
	// STRY0117951
	PREFERENCE_TREE_ORIENTATION: 'DTechApps.Tasker.treeOrientation',

	// this loads all TaskerWidgetMessage and titles that are not part of icons
	loadMessages: function() {
		var widgetMessages;
		switch (this.widgetId){
			case 'discovertasker-officehierarchy':
				widgetMessages = this._load_officehierarchy_widgetMessages();
				break;
			case 'discovertasker_dynamic_breadcrumbs':
				widgetMessages = this._load_breadcrumbs_widgetMessages();
				break;
			case 'discovertasker-widget-in-modal':
				widgetMessages = this._load_widgetInModal_widgetMessages();
				break;
		}
		return widgetMessages;
	},

	// this loads all icons, alt tags and text used in icon tooltips
	loadIcons: function() {
		var icons = {};
		switch (this.widgetId){
			case 'discovertasker-officehierarchy':
				icons = this._load_officehiearachy_icons(icons);
				icons = this._load_tree_icons(icons);
				break;
			case 'discovertasker_dynamic_breadcrumbs':
				icons = this._load_breadcrumb_icons(icons);
				break;
			case 'discovertasker-widget-in-modal':
				icons = this._load_widgetInModal_icons(icons);
		}
		return icons;
	},

	loadDefaultsAndSettings: function($sp){
		var settings;
		switch (this.widgetId){
			case 'discovertasker-officehierarchy':
				settings = this._load_officehierarch_defaultsAndSettings($sp);
				break;
		}
		return settings;
	},
	// STRY0117951
	savePreferenceOrientation: function(newTreeOrientation){
		gs.getUser().savePreference(this.PREFERENCE_TREE_ORIENTATION, newTreeOrientation);	
	},

	savePreferencePercent: function(newPercent){
		gs.getUser().savePreference(this.PREFERENCE_PERCENT, newPercent);	
	},

	savePreferenceFavorite: function(newFavorite){
		gs.getUser().savePreference(this.PREFERENCE_FAVORITE, JSON.stringify(newFavorite));	
	},	
	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN - Office Hiearachy section
	// ------------------------------------------------------------------------------------------------------------------
	_load_officehierarch_defaultsAndSettings: function($sp){
		settings = {};
		settings.page_id = $sp.getParameter("id");
		// TODO - GET THIS SETTING FROM THE OPTIONS INSTEAD OF LOOKING AT A PAGE ID
		// ONCE COMING FROM OPTIOIN, UPDATE THIS SETTING TO NOT USE PAGE ID, UPDATE
		// ALL PAGES WHERE FULL SCREEN DESIRED TO TRUE AND THE REST SHOULD BE FINE
		settings.isFullScreen = settings.page_id == 'discovertasker_ouhierarchy_full_screeen';
		settings.permissiveOn = gs.getProperty('x_153465_discovert.PermissiveOUTaskingOptions') != 'Off';
		settings.baseURL = gs.getProperty('glide.servlet.uri');
		if($sp.getPortalRecord()){
			settings.service_portal_url_suffix = $sp.getPortalRecord().getValue('url_suffix');
		} else {
			// TODO: May want to pull default from the form load here
			settings.service_portal_url_suffix = '';
		}
		// TODO - ADD TO WIDGET OPTIONS - LEFT OFF FOR NOW
		settings.include_poc_avatar = true;

		// STRY0074597 default to true, will change later if input
		settings.topOnly = true;
		var count = new GlideAggregate('x_153465_discovert_discover_office_hierarchy');
		// DFCT0010275 - use addNullQuery for a null query instead of a string value
		count.addNullQuery('parent');
		count.addAggregate('COUNT');
		count.query();
		var topHierarchy = 0;
		if(count.next())
			topHierarchy = count.getAggregate('COUNT');
		settings.topParentNeeded = topHierarchy < 1;
		// getDefaultId for user
		var orgScripts = new OrganizationalScripts();
		var defaultOUId = orgScripts.GetUserDefaultOU(gs.getUserID()) + '';
		// get top ou for the user based on default id
		var defaultOUTopId =orgScripts.getTopOUId(defaultOUId);
		settings.defaultOU = {value: defaultOUId, topId: defaultOUTopId};

		var favoriteOU = gs.getUser().getPreference(this.PREFERENCE_FAVORITE);
		if(favoriteOU){
			settings.favorite = JSON.parse(favoriteOU);
		} else {
			settings.favorite = {value: "",	topId: ""};
		}
		var selectPercent = gs.getUser().getPreference(this.PREFERENCE_PERCENT);
		if(selectPercent){
			settings.selectPercent = selectPercent;
		} else {
			settings.selectPercent = 100;
		}
		// STRY0117951
		var treeOrientation = gs.getUser().getPreference(this.PREFERENCE_TREE_ORIENTATION);
		if(treeOrientation){
			settings.treeOrientation = treeOrientation;
		} else {
			// get the default
			var defaultIsVertical = new tasking_System_Settings_Scripts().systemControlSetting().VerticalTree;
			if(defaultIsVertical){
				settings.treeOrientation = "Vertical";
			} else {
				settings.treeOrientation = "Horizontal";
			}
		}

		return settings;
	},

	_load_officehierarchy_widgetMessages: function(){
		var widgetMessages = {};
		widgetMessages["Tasker - Select Task..."] = gs.getMessage("Tasker - Select Task...");
		widgetMessages["Tasker - Organizational Unit Information"] = gs.getMessage("Tasker - Organizational Unit Information");
		widgetMessages["Tasker - List of Sub OUs"] = gs.getMessage("Tasker - List of Sub OUs");
		widgetMessages["Tasker - List of Members"] = gs.getMessage("Tasker - List of Members");
		widgetMessages["Tasker - List of Contacts"] = gs.getMessage("Tasker - List of Contacts");
		widgetMessages["Tasker - OU Reports for "] = gs.getMessage("Tasker - OU Reports for ");
		widgetMessages["Tasker - Related Tasks"] = gs.getMessage("Tasker - Related Tasks");
		widgetMessages["Tasker - Title - Request Hierarchy Update"] = gs.getMessage("Tasker - Title - Request Hierarchy Update");
		widgetMessages["Tasker - Create New Sub OU"] = gs.getMessage("Tasker - Create New Sub OU");
		widgetMessages["Tasker - Title - TASK MANAGERS"] = gs.getMessage("Tasker - Title - TASK MANAGERS");
		widgetMessages["Tasker - Title - OU HIERARCHY ADMINISTRATORS"] = gs.getMessage("Tasker - Title - OU HIERARCHY ADMINISTRATORS");
		// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
		widgetMessages['Tasker - Tasker Message: Organizational Unit: '] = gs.getMessage('Tasker - Tasker Message: Organizational Unit: ');
		widgetMessages['Tasker - Button - Message'] = gs.getMessage('Tasker - Button - Message');
		// 2.8 | 2022-03-10 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
		widgetMessages['Tasker - Open Contact Page'] = gs.getMessage('Tasker - Open Contact Page');

		widgetMessages['Tasker - Top Organization(s) Only'] = gs.getMessage('Tasker - Top Organization(s) Only');
		widgetMessages['Tasker - A top Organizational Unit needs to be created, click here to create one'] = gs.getMessage('Tasker - A top Organizational Unit needs to be created, click here to create one');
		widgetMessages['Tasker - Set selected as Favorite OU'] = gs.getMessage('Tasker - Set selected as Favorite OU');
		widgetMessages['Tasker - This is your selected Favorite OU'] = gs.getMessage('Tasker - This is your selected Favorite OU');
		widgetMessages['Tasker - Entire Tree'] = gs.getMessage('Tasker - Entire Tree');

		return widgetMessages;
	},

	_load_officehiearachy_icons: function(icons){
		// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel
		icons["BusinessPhone16"] = this._buildIcon({imageName: 'BusinessPhone16.svg',title: '',alt:''});
		icons["Mail16"] = this._buildIcon({imageName: 'Mail16.svg',title: '',alt:''});
		icons["Phone16"] = this._buildIcon({imageName: 'Phone16.svg',title: '',alt:''});
		icons["SendMessage24"] = this._buildIcon({imageName: 'SendMessage24.svg',title: '',alt:''});

		icons["taskManager"] = this._buildIcon({imageName: 'Tie16.svg', title: '', alt:''});
		icons["Admin16"] = this._buildIcon({imageName: 'Admin16.svg',title: '',alt:''});
		icons["Request16"] = this._buildIcon({imageName: 'Request16.svg', title: gs.getMessage("Tasker - Open Request Organizational Update"), alt: gs.getMessage("Tasker - Open Request")});
		icons["ProcessRequestBadge24"] = this._buildIcon({imageName: 'ProcessRequestBadge24.svg', title: gs.getMessage("Tasker - Click to respond to the Organizational Request"), alt: gs.getMessage("Tasker - Open Request List")});
		icons["Information16"] = this._buildIcon({imageName: 'Information16.svg', title: gs.getMessage("Tasker - Open Organizational Unit Information"), alt: gs.getMessage("Tasker - Open Information")});
		icons["SubOU16"] = this._buildIcon({imageName: 'SubOU16.svg', title: gs.getMessage("Tasker - Open List of Sub Organization Units"), alt: gs.getMessage("Tasker - Open Sub Organization Unit List")});
		icons["OUMembers16"] = this._buildIcon({imageName: 'OUMembers16.svg', title: gs.getMessage("Tasker - Open List of Members"), alt: gs.getMessage("Tasker - Open Member List")});
		icons["Contacts16"] = this._buildIcon({imageName: 'Contacts16.svg', title: gs.getMessage("Tasker - Open List of Contacts"), alt: gs.getMessage("Tasker - Open Contact List")});
		icons["Reports16"] = this._buildIcon({imageName: 'Reports16.svg', title: gs.getMessage("Tasker - Go to Reports"), alt: gs.getMessage("Tasker - Go to Reports")});
		icons["RelatedTasks16"] = this._buildIcon({imageName: 'RelatedTasks16.svg', title: gs.getMessage("Tasker - Open Related Tasks"), alt: gs.getMessage("Tasker - Open Task List")});
		icons["Divider"] = this._buildIcon({imageName: 'Divider.svg', title: "", alt: ""});
		icons["GenericAddSub16"] = this._buildIcon({imageName: 'GenericAddSub16.svg', title: gs.getMessage("Tasker - Create Sub OU"), alt: gs.getMessage("Tasker - Add Sub OU")});
		icons["LockOpenBadge24"] = this._buildIcon({imageName: 'LockOpenBadge24.svg', title: gs.getMessage("Tasker - Permissive Organizational Unit"), alt: gs.getMessage("Tasker - OU is Permissive")});
		// the icons below are tree view icons, but only used in OU
		icons["Favorite24"] = this._buildIcon({imageName: 'Favorite24.svg', title: gs.getMessage("Tasker - Navigate to Favorited OU"), alt: gs.getMessage("Tasker - Favorite OU")});
		icons["DefaultOU24"] = this._buildIcon({imageName: 'DefaultOU24.svg', title: gs.getMessage("Tasker - Navigate to my default OU"), alt: gs.getMessage("Tasker - Default OU")});
		icons["AddToFavorite24"] = this._buildIcon({imageName: 'AddToFavorite24.svg', title: gs.getMessage("Tasker - Set selected as Favorite OU"), alt: gs.getMessage("Tasker - Add Favorite")});
		icons["FavoriteFilled24"] = this._buildIcon({imageName: 'FavoriteFilled24.svg', title: gs.getMessage("Tasker - This is your selected Favorite OU"), alt: gs.getMessage("Tasker - Selected Favorite")});
		// the icons below are tree view icons, but the text changes in each tree
		icons["Fullscreen16"] = this._buildIcon({imageName: 'Fullscreen16.svg', title: gs.getMessage("Tasker - Maximize Organizational Hierarchy to Full Screen"), alt: gs.getMessage("Tasker - Full Screen View")});
		icons["MinimizeFullScreen16"] = this._buildIcon({imageName: 'MinimizeFullScreen16.svg', title: gs.getMessage("Tasker - Minimize Organizational Hierarchy to Split view"), alt: gs.getMessage("Tasker - Bifold View")});

		icons["TopOU24_Blue"] = this._buildIcon({imageName: 'TopOU24_Blue.svg', title: gs.getMessage("Tasker - Create Top Organizational Unit"), alt: gs.getMessage("Tasker - Create Top Organizational Unit")});

		return icons;
	},
	// ------------------------------------------------------------------------------------------------------------------
	// END - Office Hiearachy section
	// ------------------------------------------------------------------------------------------------------------------

	// ------------------------------------------------------------------------------------------------------------------
	// BEGIN - Tree Zoom Iconis
	// ------------------------------------------------------------------------------------------------------------------
	_load_tree_icons: function(icons){
		icons["OrgHierarchy24"] = this._buildIcon({imageName: 'OrgHierarchy24.svg', title: gs.getMessage("Tasker - View as Horizontal Hierarchy"), alt: gs.getMessage("Tasker - View as Horizontal Hierarchy")});
		icons["OrgHierarchy-Vertical24"] = this._buildIcon({imageName: 'OrgHierarchy-Vertical24.svg', title: gs.getMessage("Tasker - View as Vertical Hierarchy"), alt: gs.getMessage("Tasker - View as Vertical Hierarchy")});
		icons["Divider_Black"] = this._buildIcon({imageName: 'Divider_Black.svg', title: "", alt: ""});		
		icons["ZoomEntire24"] = this._buildIcon({imageName: 'ZoomEntire24.svg', title: gs.getMessage("Tasker - View the Entire Organization"), alt: gs.getMessage("Tasker - Entire Organization")});
		icons["ZoomSelected24"] = this._buildIcon({imageName: 'ZoomSelected24.svg', title: gs.getMessage("Tasker - Zoom into Selected OU"), alt: gs.getMessage("Tasker - Selected OU")});
		icons["Top24"] = this._buildIcon({imageName: 'TopOU24.svg', title: gs.getMessage("Tasker - Navigate to Top"), alt: gs.getMessage("Tasker - Go to Top")});
		return icons;
	},
	// ------------------------------------------------------------------------------------------------------------------
	// END - Tree Zoom Iconis
	// ------------------------------------------------------------------------------------------------------------------

	// STRY0117947 
	_load_breadcrumbs_widgetMessages: function(){
		var widgetMessages = {};
		widgetMessages['Tasker - Portal'] = gs.getMessage('Tasker - goToPortal (Portal)');
		widgetMessages['Tasker - Home'] = gs.getMessage('Tasker - Home');
		return widgetMessages;
	},

	// STRY0117947 
	_load_breadcrumb_icons: function(icons){
		icons["BackArrow16"] = this._buildIcon({imageName: 'BackArrow16.svg', title: '', alt:''});

		return icons;

	},

	// STRY0117947 
	_load_widgetInModal_widgetMessages: function(){
		var widgetMessages = {};
		widgetMessages['Tasker - Portal'] = gs.getMessage('Tasker - goToPortal (Portal)');
		return widgetMessages;
	},
	// STRY0117947 
	_load_widgetInModal_icons: function(icons){
		icons["BackArrow16"] = this._buildIcon({imageName: 'BackArrow16.svg', title: '', alt:''});
		icons["Office24"] = this._buildIcon({imageName: 'Office24.svg', title: gs.getMessage("Tasker - My Offices"), alt: gs.getMessage("Tasker - My Offices")});

		return icons;

	},

	//------------------------------------------------------------------------------------------------------------------------
	// buildIcon({
	//				imageName: [image name in db_image table],
	//				title: [TaskerWidgetIconsAndMessagessage key or text for the tooltip for icon],
	//				alt:' [TaskerWidgetIconsAndMessagessage key or text for the alt value]
	//           })
	_buildIcon: function(params){
		var grImage = new GlideRecord("db_image");
		var image;
		grImage.addQuery('name',params.imageName);
		grImage.query();
		if(grImage.next()){
			image=grImage.getDisplayValue();
		}
		var icon = {
			src:image, 
			title: gs.getMessage(params.title), 
			alt:gs.getMessage(params.alt)
		};		
		return icon;
	},

    type: 'TaskerWidgetIconsAndMessages'
};
